local LBattleViewBuffActQueue = classX("LBattleViewBuffActQueue", nil)

local LBattleBuffActData = require("LApp.gameplay.videobattle.data.LBattleBuffActData")
local LBattleBuffActDrawing = require("LApp.gameplay.videobattle.view.buffact.LBattleBuffActDrawing")
local LBattleBuffActEffect = require("LApp.gameplay.videobattle.view.buffact.LBattleBuffActEffect")
local LBattleBuffActRole = require("LApp.gameplay.videobattle.view.buffact.LBattleBuffActRole")
local LBattleBuffActShake = require("LApp.gameplay.videobattle.view.buffact.LBattleBuffActShake")
local LBattleBuffActTransform = require("LApp.gameplay.videobattle.view.buffact.LBattleBuffActTransform")

function LBattleViewBuffActQueue:ctor(expressId, viewMgr)
    ---@type LBattleViewMgr
    self._viewMgr = viewMgr
    self._expressId = expressId

    local buffExpressData = LBattleBuffActData:new()
    buffExpressData:SetData(self._expressId)

    ---@type LBattleBuffActData
    self._buffActData = buffExpressData

    ---@type LBattleBuffActBase[]
    self._expressionList = nil

    ---@type LBattleBuffActTransform[]
    self._expressionsTransformList = nil
end

function LBattleViewBuffActQueue:Initialize()
    local playList = self._buffActData:GetPlayList()
    local expressionsTransformList = {}
    local expressionsList = {}
    local expre = nil
    for k,v in ipairs(playList) do
        expre = nil
        if v.effType == LSkillEffConst.PLAY_EFF_ANI then
            expre = LBattleBuffActRole:new(self._viewMgr)
            expre:Create(v)
        elseif v.effType == LSkillEffConst.PLAY_EFF_EFFECT then
            expre = LBattleBuffActEffect:new(self._viewMgr)
            expre:Create(v)
        elseif v.effType == LSkillEffConst.PLAY_EFF_DRAWING then
            expre = LBattleBuffActDrawing:new(self._viewMgr)
            expre:Create(v)
        elseif v.effType == LSkillEffConst.PLAY_EFF_SHAKE then
            expre = LBattleBuffActShake:new(self._viewMgr)
            expre:Create(v)
        end
        if expre then
            table.insert(expressionsList,expre)
        end

        if v.effType == LSkillEffConst.PLAY_OBJ_TRANSFORM then
            local tExpre = LBattleBuffActTransform:new(self._viewMgr)
            tExpre:Create(v)
            table.insert(expressionsTransformList,tExpre)
        end
    end

    self._expressionList = expressionsList

    self._expressionsTransformList = expressionsTransformList
end

function LBattleViewBuffActQueue:Preload()
    if self._expressionList then
        for k,v in ipairs(self._expressionList) do
            v:Preload()
        end
    end
    if self._expressionsTransformList then
        for i,v in ipairs(self._expressionsTransformList) do
            v:Preload()
        end
    end
end

function LBattleViewBuffActQueue:StartRun(data)
    --local time = data.curTime
    ---@type LFightObject
    local targetObj = data.targetObj
    ---@type LFightObject
    self._targetObj = targetObj
    --if targetObj then
    --    targetObj:SetSkillPlaying(true)
    --end

    self._buffEffShowPos = data.buffEffShowPos

    self._atkObj = data.atkObj

    self._isStart = false

    self:OnUpdate(data.curTime, 0)

end

function LBattleViewBuffActQueue:CheckReady()
    if not self._targetObj then
        return
    end

    if not self._targetObj:IsObjReady() then
        return
    end

    return true
end

function LBattleViewBuffActQueue:StartRunInter(time)
    if self._isStart then
        return
    end
    self._isStart = true

    local targetObj = self._targetObj
    local rundata = nil
    for k,v in pairs(self._expressionList) do
        local type = v:GetType()
        if type == LSkillEffConst.PLAY_EFF_ANI then
            rundata = {
                curTime = time,
                targetObj = targetObj,
            }
            v:BeginRunning(rundata)
        elseif type == LSkillEffConst.PLAY_EFF_EFFECT then
            local pos = targetObj:GetPosition():Clone()
            local buffEffShowPos = self._buffEffShowPos
            if buffEffShowPos and buffEffShowPos > 0 and not targetObj:GetChangeSpineState() then
                local buffShowPos = targetObj:GetBuffEffShowPosByBuffEffShowPos(buffEffShowPos,targetObj:GetObjScale())
                if buffShowPos then
                    pos = buffShowPos
                end
            end
            local isChangeSpine = targetObj:GetChangeSpineState()
            local rootTrans = self._viewMgr:GetEffectRootTrans()
            local trans = isChangeSpine and rootTrans or targetObj:GetDpObject():GetDpTrans()
            local effpara = {
                trans = trans,
                pos = pos,
                dir = targetObj:GetDirection(),
            }
            rundata = {
                curTime = time,
                isUpperLayer = targetObj:IsUpperLayer(),
                dataList = { effpara }
            }
            v:BeginRunning(rundata)
        elseif type == LSkillEffConst.PLAY_EFF_DRAWING then
            rundata = {
                curTime = time,
                targetObj = targetObj,
                atkObj = self._atkObj,
            }
            v:BeginRunning(rundata)
        elseif type == LSkillEffConst.PLAY_EFF_SHAKE then
            rundata = {
                curTime = time,
                targetObj = targetObj,
                atkObj = self._atkObj,
            }
            v:BeginRunning(rundata)
        end
    end
    for i,v in ipairs(self._expressionsTransformList) do
        v:BeginRunning({
            curTime = time,
            targetObj = targetObj,
            atkObj = self._atkObj,
        })
    end
end

function LBattleViewBuffActQueue:OnUpdate(time, deltaTime)
    if not self._expressionList then
        return
    end

    if self:CheckReady() then
        self:StartRunInter(time)
    end

    for k,v in ipairs(self._expressionList) do
        v:OnUpdate(time,deltaTime)
    end

    if self._expressionsTransformList then
        for k,v in ipairs(self._expressionsTransformList) do
            v:OnUpdate(time, deltaTime)
        end
    end
end

function LBattleViewBuffActQueue:GetExpressId()
    return self._expressId
end

function LBattleViewBuffActQueue:Dispose()
    if self._expressionList then
        for k,v in ipairs(self._expressionList) do
            v:Dispose()
        end
        self._expressionList = nil
    end
    if self._expressionsTransformList then
        for i,v in ipairs(self._expressionsTransformList) do
            v:Dispose()
        end
        self._expressionsTransformList = nil
    end
end

function LBattleViewBuffActQueue:IsEnd()

    for k,v in ipairs(self._expressionList) do
        if not v:IsEnd() then
            return false
        end
    end

    if self._expressionsTransformList then
        for i,v in ipairs(self._expressionsTransformList) do
            if not v:IsEnd() then
                return false
            end
        end
    end

    return true
end

function LBattleViewBuffActQueue:OnRecycle()
    for k,v in ipairs(self._expressionList) do
        v:OnRecycle()
    end

    if self._expressionsTransformList then
        for i,v in ipairs(self._expressionsTransformList) do
            v:OnRecycle()
        end
    end
end

function LBattleViewBuffActQueue:OnPlayEnd()
    local targetObj = self._targetObj
    if targetObj then
        targetObj:SetSkillPlaying(false)
    end
end

return LBattleViewBuffActQueue